des = 1 - dis*.7071068;;
des = pow(des,8)*-treb;;
an = acos(abs(xd)/dis);;
dx = sign(xd)*.07*cos(an)*des;;
dy = sign(yd)*.07*sin(an)*des;;
dy = dy + sign(xd)*treb*.05*cos(an)*des;;
dx = dx + sign(yd)*treb*.05*sin(an)*des*-1;;
